#!/usr/bin/env python3

def xor_decrypt(ciphertext_hex, key):
    # Convert the key to bytes
    key_bytes = key.encode()

    # Convert the ciphertext from hex to bytes
    ciphertext_bytes = bytes.fromhex(ciphertext_hex)

    # Repeat the key to match the length of the ciphertext
    repeated_key = (key_bytes * (len(ciphertext_bytes) // len(key_bytes) + 1))[:len(ciphertext_bytes)]

    # Perform the XOR operation
    decrypted_bytes = bytes([a ^ b for a, b in zip(ciphertext_bytes, repeated_key)])

    return decrypted_bytes

ciphertext_hex = ""

key = "OpenAIisAmazingOpenAIisAmazing"

print(xor_decrypt(ciphertext_hex, key))
